class PdfSignatureFieldWidget(PdfStyledFieldWidget):
    """
    Represents the signature field of an existing PDF document's form.
    """

    @property
    def Signature(self):
        from spire.pdf.security.Security_PdfSignature import Security_PdfSignature
        """
        Returns the signature of the signature field.
        """
        GetDllLibPdf().spr_pdf_PdfSignatureFieldWidget_get_Signature.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfSignatureFieldWidget_get_Signature.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfSignatureFieldWidget_get_Signature,self.Ptr)
        ret = None if intPtr == None else Security_PdfSignature(intPtr)
        return ret

    @Signature.setter
    def Signature(self, value):
        """
        Sets the signature of the signature field.
        """
        GetDllLibPdf().spr_pdf_PdfSignatureFieldWidget_set_Signature.argtypes = [c_void_p, c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfSignatureFieldWidget_set_Signature,self.Ptr, value.Ptr)

